import {
  type CSSProperties,
  forwardRef,
  type HTMLAttributes,
  type ReactNode,
  useEffect,
  useId,
  useState,
} from 'react';
import {
  FloatingFocusManager,
  FloatingOverlay,
  FloatingPortal,
  useDismiss,
  useFloating,
  useInteractions,
  useRole,
} from '@floating-ui/react';
import { cls, useNamespace } from '../../utils';

function CloseIcon() {
  return (
    <svg viewBox="0 0 24 24" width="1em" height="1em" aria-hidden="true" focusable="false">
      <path
        fill="currentColor"
        d="M13.41 12l5.3-5.29a1 1 0 1 0-1.42-1.42L12 10.59l-5.29-5.3a1 1 0 0 0-1.42 1.42l5.3 5.29-5.3 5.29a1 1 0 0 0 0 1.42 1 1 0 0 0 1.42 0L12 13.41l5.29 5.3a1 1 0 0 0 1.42 0 1 1 0 0 0 0-1.42z"
      />
    </svg>
  );
}

export interface DialogProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
  /** Controlled visibility. */
  open: boolean;
  /** Called when the dialog requests to close (escape, overlay click, close button). */
  onClose?: () => void;
  /** Called whenever the open state should change. */
  onOpenChange?: (open: boolean) => void;
  /** Title shown in the header. Ignored when `header` is provided. */
  title?: ReactNode;
  /** Custom header content; overrides the title area. */
  header?: ReactNode;
  /** Footer content. */
  footer?: ReactNode;
  /** Dialog width. Default `'50%'`. */
  width?: string | number;
  /** Take up the whole viewport. */
  fullscreen?: boolean;
  /** Distance from the top of the viewport. Ignored when `alignCenter`/`fullscreen`. Default `'15vh'`. */
  top?: string;
  /** Vertically center the dialog. */
  alignCenter?: boolean;
  /** Show the backdrop. Default `true`. */
  modal?: boolean;
  /** Close when clicking the overlay. Default `true`. */
  closeOnClickModal?: boolean;
  /** Close when pressing Escape. Default `true`. */
  closeOnPressEscape?: boolean;
  /** Show the close button. Default `true`. */
  showClose?: boolean;
  /**
   * Intercept a close request. Receives a `done` callback; the dialog only
   * closes (firing `onClose`/`onOpenChange(false)`) once `done()` is invoked,
   * allowing async confirmation. Applies to escape, overlay click and the close
   * button. Mirrors Element Plus's `before-close`.
   */
  beforeClose?: (done: () => void) => void;
  /** Center the header and footer text. */
  center?: boolean;
  /** Lock body scroll while open. Default `true`. */
  lockScroll?: boolean;
  /** Always portal to `document.body` (kept for API parity). */
  appendTo?: unknown;
  /** Keep the dialog mounted while closed. Default `false`. */
  keepMounted?: boolean;
  /** Destroy the body content every time the dialog closes. */
  destroyOnClose?: boolean;
  children?: ReactNode;
}

export const Dialog = forwardRef<HTMLDivElement, DialogProps>(function Dialog(props, ref) {
  const {
    open,
    onClose,
    onOpenChange,
    title,
    header,
    footer,
    width = '50%',
    fullscreen = false,
    top = '15vh',
    alignCenter = false,
    modal = true,
    closeOnClickModal = true,
    closeOnPressEscape = true,
    showClose = true,
    center = false,
    lockScroll = true,
    keepMounted = false,
    destroyOnClose = false,
    beforeClose,
    appendTo: _appendTo,
    className,
    style,
    children,
    ...rest
  } = props;

  const ns = useNamespace('dialog');
  const reactId = useId();
  const titleId = `${ns.b()}-title-${reactId}`;

  // Track whether the body has ever been opened, for destroyOnClose semantics.
  const [renderedOnce, setRenderedOnce] = useState(open);
  useEffect(() => {
    if (open) setRenderedOnce(true);
    else if (destroyOnClose) setRenderedOnce(false);
  }, [open, destroyOnClose]);

  const emitClose = () => {
    onOpenChange?.(false);
    onClose?.();
  };

  const requestClose = () => {
    if (beforeClose) {
      beforeClose(emitClose);
    } else {
      emitClose();
    }
  };

  const handleOpenChange = (next: boolean) => {
    if (next) {
      onOpenChange?.(true);
    } else {
      requestClose();
    }
  };

  const { refs, context } = useFloating({
    open,
    onOpenChange: handleOpenChange,
  });

  const dismiss = useDismiss(context, {
    // In non-modal mode no mask is rendered, so there is no overlay to click
    // "outside" of; only the escape key can dismiss.
    outsidePress: modal && closeOnClickModal,
    escapeKey: closeOnPressEscape,
  });
  const role = useRole(context, { role: 'dialog' });
  const { getFloatingProps } = useInteractions([dismiss, role]);

  if (!open && !keepMounted) return null;

  const panelClasses = cls(
    ns.b(),
    ns.is('fullscreen', fullscreen),
    ns.is('center', center),
    ns.is('align-center', alignCenter && !fullscreen),
    className,
  );

  const widthValue = typeof width === 'number' ? `${width}px` : width;
  const panelStyle: CSSProperties = {
    [ns.cssVar('width')]: fullscreen ? undefined : widthValue,
    marginTop: fullscreen || alignCenter ? undefined : top,
    ...style,
  } as CSSProperties;

  const showBody = open || (keepMounted && !destroyOnClose) || renderedOnce;

  const {
    'aria-label': ariaLabel,
    'aria-labelledby': ariaLabelledByProp,
    ...restProps
  } = rest as HTMLAttributes<HTMLDivElement>;

  // Always expose an accessible name: prefer a consumer-supplied
  // aria-labelledby/aria-label, otherwise reference the rendered header (custom
  // `header` slot or the default `title`) via its id.
  const hasInternalLabel = header != null || title != null;
  const ariaLabelledBy =
    ariaLabelledByProp ?? (!ariaLabel && hasInternalLabel ? titleId : undefined);

  const renderHeaderContent = () =>
    header != null ? (
      <span id={titleId} className={ns.e('header-content')}>
        {header}
      </span>
    ) : (
      <span id={titleId} className={ns.e('title')}>
        {title}
      </span>
    );

  const panel = (
    <FloatingFocusManager context={context} modal={modal} initialFocus={refs.floating}>
      <div
        ref={(node) => {
          refs.setFloating(node);
          if (typeof ref === 'function') ref(node);
          else if (ref) ref.current = node;
        }}
        className={panelClasses}
        style={panelStyle}
        role="dialog"
        aria-modal={modal || undefined}
        aria-label={ariaLabel}
        aria-labelledby={ariaLabelledBy}
        {...getFloatingProps(restProps)}
      >
        <div className={cls(ns.e('header'), ns.is('with-close', showClose))}>
          {renderHeaderContent()}
          {showClose && (
            <button
              type="button"
              className={ns.e('headerbtn')}
              aria-label="Close"
              onClick={requestClose}
            >
              <CloseIcon />
            </button>
          )}
        </div>
        <div className={ns.e('body')}>{showBody ? children : null}</div>
        {footer != null && <div className={ns.e('footer')}>{footer}</div>}
      </div>
    </FloatingFocusManager>
  );

  return (
    <FloatingPortal>
      {(open || keepMounted) &&
        (modal ? (
          <FloatingOverlay
            className={cls('ec-overlay', ns.is('hidden', !open), ns.e('mask'))}
            lockScroll={lockScroll && open}
            style={{
              display: open ? undefined : 'none',
              zIndex: 'var(--ec-index-popper)' as unknown as number,
            }}
          >
            <div
              className={cls(ns.e('wrapper'), ns.is('align-center', alignCenter && !fullscreen))}
            >
              {panel}
            </div>
          </FloatingOverlay>
        ) : (
          // Non-modal: render no full-screen hit-testing overlay so the page
          // behind stays interactive. The wrapper centers the panel but lets
          // pointer events fall through except over the panel itself.
          <div
            className={cls(
              'ec-overlay',
              ns.e('wrapper'),
              ns.is('non-modal'),
              ns.is('hidden', !open),
              ns.is('align-center', alignCenter && !fullscreen),
            )}
            style={{
              display: open ? undefined : 'none',
              zIndex: 'var(--ec-index-popper)' as unknown as number,
            }}
          >
            {panel}
          </div>
        ))}
    </FloatingPortal>
  );
});

.ec-overlay {
  position: fixed;
  inset: 0;
  z-index: var(--ec-index-popper);
  overflow: auto;
}

.ec-dialog__mask {
  background-color: var(--ec-dialog-overlay-color);
  animation: ec-dialog-fade-in var(--ec-transition-duration) var(--ec-transition-function-fast-bezier);
}

.ec-dialog__wrapper {
  display: flex;
  flex-direction: column;
  align-items: center;
  box-sizing: border-box;
  min-height: 100%;
  padding-bottom: 4vh;
}

.ec-dialog__wrapper.is-align-center {
  justify-content: center;
  padding-bottom: 0;
}

/*
 * Non-modal dialog: no masking layer is rendered, so the full-screen wrapper
 * must let pointer events fall through to the page behind it. Only the dialog
 * panel itself re-enables pointer events.
 */
.ec-dialog__wrapper.is-non-modal {
  pointer-events: none;
}

.ec-dialog__wrapper.is-non-modal .ec-dialog {
  pointer-events: auto;
}

.ec-dialog {
  --ec-dialog-width: 50%;
  --ec-dialog-padding-primary: 16px;
  --ec-dialog-overlay-color: rgba(0, 0, 0, 0.5);
  --ec-dialog-bg-color: var(--ec-bg-color);
  --ec-dialog-title-font-size: var(--ec-font-size-large);
  --ec-dialog-content-font-size: var(--ec-font-size-base);
  --ec-dialog-font-line-height: 1.5;
  --ec-dialog-box-shadow: var(--ec-box-shadow);

  position: relative;
  box-sizing: border-box;
  width: var(--ec-dialog-width);
  max-width: calc(100% - 32px);
  padding: var(--ec-dialog-padding-primary);
  background-color: var(--ec-dialog-bg-color);
  border-radius: var(--ec-border-radius-base);
  box-shadow: var(--ec-dialog-box-shadow);
  color: var(--ec-text-color-regular);
  font-family: var(--ec-font-family);
  font-size: var(--ec-dialog-content-font-size);
  word-break: break-all;
  outline: none;
  animation: ec-dialog-zoom-in var(--ec-transition-duration) var(--ec-transition-function-fast-bezier);
}

.ec-dialog.is-fullscreen {
  --ec-dialog-width: 100%;

  margin: 0;
  max-width: 100%;
  min-height: 100%;
  border-radius: 0;
  overflow: auto;
}

.ec-dialog.is-align-center {
  margin: 0;
}

.ec-dialog__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  margin-bottom: var(--ec-dialog-padding-primary);
  padding-right: 0;
}

.ec-dialog.is-center .ec-dialog__header {
  justify-content: center;
  text-align: center;
}

.ec-dialog__title {
  flex: 1;
  font-size: var(--ec-dialog-title-font-size);
  line-height: var(--ec-dialog-font-line-height);
  color: var(--ec-text-color-primary);
}

.ec-dialog.is-center .ec-dialog__title {
  flex: none;
}

.ec-dialog__headerbtn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  width: 24px;
  height: 24px;
  padding: 0;
  margin: 0;
  font-size: 16px;
  background: transparent;
  border: none;
  outline: none;
  cursor: pointer;
  color: var(--ec-text-color-secondary);
  transition: var(--ec-transition-color);
}

.ec-dialog__headerbtn:hover {
  color: var(--ec-color-primary);
}

.ec-dialog__headerbtn:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: 1px;
}

.ec-dialog__body {
  font-size: var(--ec-dialog-content-font-size);
  line-height: var(--ec-dialog-font-line-height);
  color: var(--ec-text-color-regular);
}

.ec-dialog__footer {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 8px;
  margin-top: var(--ec-dialog-padding-primary);
  box-sizing: border-box;
}

.ec-dialog.is-center .ec-dialog__footer {
  justify-content: center;
}

@keyframes ec-dialog-fade-in {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes ec-dialog-zoom-in {
  from {
    opacity: 0;
    transform: translateY(-20px) scale(0.95);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}
